// Extract email metadata for synthesis
const items = $input.all();
const emails = items.map(item => {
  const headers = item.json.payload?.headers || [];
  const getHeader = (name) => headers.find(h => h.name.toLowerCase() === name.toLowerCase())?.value || '';

  return {
    from: getHeader('From'),
    subject: getHeader('Subject'),
    date: getHeader('Date'),
    snippet: item.json.snippet || ''
  };
});

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  timeZone: 'Asia/Jakarta'
});

let emailList = 'No new emails.';
if (emails.length > 0) {
  emailList = emails.map((e, i) => 
    `${i + 1}. From: ${e.from}\n   Subject: ${e.subject}\n   Preview: ${e.snippet}`
  ).join('\n\n');
}

const prompt = `You are Jarvis, a personal executive assistant. Synthesize the following emails received in the last 24 hours for ${today}.

Provide:
1. A brief summary (2-3 sentences) of the overall email activity
2. List any IMPORTANT items that need attention (action required, decisions needed)
3. List any DEADLINES mentioned in the emails
4. Flag anything that looks urgent

Keep it concise and actionable. Under 200 words total.

--- EMAILS (${emails.length} total) ---

${emailList}

IMPORTANT: If there are no actionable emails, say so briefly. Do not fabricate information.`;

return [{
  json: {
    prompt,
    emailCount: emails.length,
    today
  }
}];

const response = $input.first().json;
const synthesisText = response.content?.[0]?.text || response.text || JSON.stringify(response);
const today = new Date().toISOString().split('T')[0];

// Count important items and deadlines from the synthesis
const importantMatch = synthesisText.match(/important|action required|urgent|attention/gi);
const deadlineMatch = synthesisText.match(/deadline|due|by (monday|tuesday|wednesday|thursday|friday|saturday|sunday|tomorrow|end of)/gi);

return [{
  json: {
    date: today,
    synthesis_text: synthesisText,
    important_count: importantMatch ? Math.min(importantMatch.length, 10) : 0,
    deadline_count: deadlineMatch ? Math.min(deadlineMatch.length, 10) : 0,
    created_at: new Date().toISOString()
  }
}];
